  editHabit:function(id){var h=(STATE.habits||[]).find(function(x){return x.id===id});if(!h)return '';return '<h2>&#9998;&#65039; Edit habit</h2><div class="field"><label>Habit name</label><input id="m-hname" value="'+h.name.replace(/"/g,'&quot;')+'"></div><div class="field-row"><div class="field"><label>Frequency</label><select id="m-hfreq"><option'+(h.freq==='daily'?' selected':'')+'>daily</option><option'+(h.freq==='3x/week'?' selected':'')+'>3x/week</option><option'+(h.freq==='weekly'?' selected':'')+'>weekly</option><option'+(h.freq==='bi-monthly'?' selected':'')+'>bi-monthly</option><option'+(h.freq==='monthly'?' selected':'')+'>monthly</option></select></div><div class="field"><label>Category</label><select id="m-hbadge"><option value="fit"'+(h.badge==='fit'?' selected':'')+'>Fitness</option><option value="fin"'+(h.badge==='fin'?' selected':'')+'>Finance</option><option value="car"'+(h.badge==='car'?' selected':'')+'>Career</option><option value="per"'+(h.badge==='per'?' selected':'')+'>Personal</option></select></div></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-danger" onclick="deleteHabit(\''+id+'\')">Delete</button><button class="btn btn-accent" onclick="updateHabit(\''+id+'\')">Save &#10003;</button></div>'},
