  editIncome:function(id){var i=(STATE.income||[]).find(function(x){return x.id===id});if(!i)return '';return '<h2>Edit income</h2><div class="field-row"><div class="field"><label>Name</label><input id="m-iname" value="'+i.name+'"></div><div class="field"><label>Icon</label><input id="m-iicon" value="'+(i.icon||'&#128188;')+'" maxlength="2"></div></div><div class="field"><label>Amount (&#163;/month)</label><input id="m-iamount" type="number" value="'+i.amount+'" step="0.01"></div><div class="field"><label>Note</label><input id="m-inote" value="'+(i.note||'')+'"></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="updateIncome(\''+id+'\')">Save &#10003;</button></div>'},
  addExpense:function(){return '<h2>&#128308; Add expense</h2><div class="field-row"><div class="field"><label>Name</label><input id="m-ename" placeholder="e.g. Rent"></div><div class="field"><label>Icon</label><input id="m-eicon" placeholder="&#127968;" maxlength="2"></div></div><div class="field"><label>Amount (&#163;/month)</label><input id="m-eamount" type="number" step="0.01" placeholder="0"></div><div class="field"><label>Note</label><input id="m-enote" placeholder="optional"></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="saveExpense()">Add &#10003;</button></div>'},
  editExpense:function(id){var e=(STATE.expenses||[]).find(function(x){return x.id===id});if(!e)return '';return '<h2>Edit expense</h2><div class="field-row"><div class="field"><label>Name</label><input id="m-ename" value="'+e.name+'"></div><div class="field"><label>Icon</label><input id="m-eicon" value="'+(e.icon||'&#128184;')+'" maxlength="2"></div></div><div class="field"><label>Amount</label><input id="m-eamount" type="number" value="'+e.amount+'" step="0.01"></div><div class="field"><label>Note</label><input id="m-enote" value="'+(e.note||'')+'"></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="updateExpense(\''+id+'\')">Save &#10003;</button></div>'},
