  addProjectTask:function(id){return '<h2>Add task</h2><div class="field"><label>Task</label><input id="m-ptask" placeholder="e.g. Write section 2"></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="saveProjectTask(\''+id+'\')">Add</button></div>'},
