  editRelationship:function(id){var r=(STATE.relationships||[]).find(function(x){return x.id===id});if(!r)return '';return '<h2>Edit</h2><div class="field-row"><div class="field"><label>Name</label><input id="m-rname" value="'+r.name.replace(/"/g,'&quot;')+'"></div><div class="field"><label>Icon</label><input id="m-ricon" value="'+(r.icon||'&#128100;')+'" maxlength="2"></div></div><div class="field-row"><div class="field"><label>Check-in every (days)</label><input id="m-rfreq" type="number" value="'+r.freq+'"></div><div class="field"><label>Note</label><input id="m-rnote" value="'+(r.note||'').replace(/"/g,'&quot;')+'"></div></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="updateRelationship(\''+id+'\')">Save</button></div>'},
