var hyroxState=JSON.parse(localStorage.getItem('hyrox_v2')||'{}');
var hyroxCurrentPlan='standard';

function hyroxKey(plan,w,d){return plan+'_w'+w+'_d'+d}

function hyroxUpdateProgress(){
  var plan=hyroxPlans[hyroxCurrentPlan];
  var total=0,done=0;
  plan.forEach(function(wk,wi){
    wk.days.forEach(function(d,di){if(!d.rest){total++;if(hyroxState[hyroxKey(hyroxCurrentPlan,wi,di)])done++}});
    var card=document.querySelector('[data-hxwk="'+hyroxCurrentPlan+'-'+wi+'"]');
    if(card){
      var dotEls=card.querySelectorAll('.hx2-dot');
      var dotIdx=0;
      wk.days.forEach(function(d,di){
        if(d.rest)return;
        var dot=dotEls[dotIdx];dotIdx++;
        if(dot)dot.style.background=hyroxState[hyroxKey(hyroxCurrentPlan,wi,di)]?'var(--gold)':'var(--bg4)';
      });
      var wDone=wk.days.filter(function(d,di){return !d.rest&&hyroxState[hyroxKey(hyroxCurrentPlan,wi,di)]}).length;
      var wTotal=wk.days.filter(function(d){return !d.rest}).length;
      card.classList.toggle('hx2-complete',wDone===wTotal);
    }
  });
  var pct=total?Math.round(done/total*100):0;
  var f=document.getElementById('hxProgFill2');if(f)f.style.width=pct+'%';
  var l=document.getElementById('hxProgLabel2');if(l)l.textContent=done+' / '+total;
}

function hyroxToggleDay(plan,w,d){
  var key=hyroxKey(plan,w,d);
  var wkData=hyroxPlans[plan][w];
  var day=wkData.days[d];
  if(day.rest)return;
  if(hyroxState[key]){
    hyroxState[key]=false;
    localStorage.setItem('hyrox_v2',JSON.stringify(hyroxState));
    hyroxUpdateProgress();
    var row=document.querySelector('[data-hxday2="'+key+'"]');
    if(row)row.classList.remove('hx2-ticked');
    return;
  }
  var mc=document.getElementById('modal-content');
  mc.innerHTML='<h2>⚡ Log Hyrox Session</h2><div class="modal-sub">Week '+wkData.week+' · '+day.label+'</div><div class="field"><label>Date completed</label><input id="m-hxdate" type="date" value="'+localDateKey(new Date())+'"></div><div class="modal-btns"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-accent" onclick="hyroxConfirmLog(\''+plan+'\','+w+','+d+')">Log ✓</button></div>';
  document.getElementById('modal').style.display='flex';
}
function hyroxConfirmLog(plan,w,d){
  var key=hyroxKey(plan,w,d);
  var wkData=hyroxPlans[plan][w];
  var day=wkData.days[d];
  var date=(document.getElementById('m-hxdate')||{}).value||localDateKey(new Date());
  hyroxState[key]=true;
  localStorage.setItem('hyrox_v2',JSON.stringify(hyroxState));
  var sess={id:g(),name:'Hyrox W'+wkData.week+' '+day.label,date:date,muscleGroups:['Hyrox'],exercises:[]};
  if(!STATE.workouts)STATE.workouts=[];
  STATE.workouts.push(sess);
  saveState();
  closeModal();
  hyroxUpdateProgress();
  var row=document.querySelector('[data-hxday2="'+key+'"]');
  if(row)row.classList.add('hx2-ticked');
  renderWorkout();
}

function hyroxToggleExpand(plan,w,d){
  var row=document.querySelector('[data-hxday2="'+hyroxKey(plan,w,d)+'"]');
  if(row)row.classList.toggle('hx2-expanded');
}

function hyroxResetAll(){
  if(!confirm('Reset all Hyrox progress?'))return;
  hyroxState={};localStorage.setItem('hyrox_v2',JSON.stringify(hyroxState));
  document.querySelectorAll('.hx2-day-row').forEach(function(r){r.classList.remove('hx2-ticked','hx2-expanded')});
  hyroxUpdateProgress();
}

function hyroxSwitchPlan(plan,btn){
  hyroxCurrentPlan=plan;
  document.querySelectorAll('.filter-btn').forEach(function(b){if(b.id==='hxPlanBtn1'||b.id==='hxPlanBtn2')b.classList.remove('active')});
  btn.classList.add('active');
  var s=document.getElementById('hxWeeksStandard');
  var p=document.getElementById('hxWeeksPro');
  if(s)s.style.display=plan==='standard'?'flex':'none';
  if(p)p.style.display=plan==='pro'?'flex':'none';
  hyroxUpdateProgress();
}

function hyroxSection(label,text){
  if(!text)return'';
  return'<div style="font-size:9px;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--gold);margin:10px 0 4px">'+label+'</div><div style="font-size:12px;line-height:1.8;color:var(--text2);white-space:pre-line">'+text+'</div>';
}

function hyroxRenderPlan(planKey){
  var cid=planKey==='standard'?'hxWeeksStandard':'hxWeeksPro';
  var container=document.getElementById(cid);
  if(!container)return;
  container.innerHTML='';
  hyroxPlans[planKey].forEach(function(wkData,wi){
    var card=document.createElement('div');
    card.style.cssText='background:var(--bg2);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden;transition:border-color .2s';
    card.dataset.hxwk=planKey+'-'+wi;
    /* Count completed days for this week */
    var totalDays=0;var doneDays=0;
    wkData.days.forEach(function(d,di){if(!d.rest){totalDays++;if(hyroxState[hyroxKey(planKey,wi,di)])doneDays++}});
    var weekPct=totalDays>0?Math.round(doneDays/totalDays*100):0;
    var dots=wkData.days.map(function(d,di){
      if(d.rest)return '';
      return '<div style="width:10px;height:10px;border-radius:50%;background:'+(hyroxState[hyroxKey(planKey,wi,di)]?'var(--gold)':'var(--bg4)')+';transition:background .2s"></div>';
    }).join('');
    /* Week header */
    card.innerHTML='<div style="padding:14px 20px;background:var(--bg3);display:flex;align-items:center;justify-content:space-between;cursor:pointer;user-select:none;gap:12px" onclick="this.parentElement.classList.toggle(\'hx2-open\');this.querySelector(\'.hx2-chev\').textContent=this.parentElement.classList.contains(\'hx2-open\')?\'▲\':\'▼\';this.parentElement.querySelector(\'.hx2-days\').style.display=this.parentElement.classList.contains(\'hx2-open\')?\'grid\':\'none\'">'
      +'<div style="display:flex;align-items:center;gap:12px"><div style="font-family:var(--serif);font-size:18px;font-weight:600;color:var(--warm-brown)">Week '+wkData.week+'</div><div style="display:flex;gap:4px">'+dots+'</div></div>'
      +'<div style="display:flex;align-items:center;gap:12px"><span style="font-size:11px;font-weight:600;color:'+(weekPct>=100?'var(--mint)':'var(--text3)')+'">'+doneDays+'/'+totalDays+'</span><div class="hx2-chev" style="font-size:10px;color:var(--text3)">▼</div></div>'
      +'</div>'
      +'<div class="hx2-days" style="display:none;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:0"></div>';
    var dc=card.querySelector('.hx2-days');
    wkData.days.forEach(function(day,di){
      var key=hyroxKey(planKey,wi,di);
      var row=document.createElement('div');
      row.className='hx2-day-row'+(hyroxState[key]?' hx2-ticked':'');
      row.dataset.hxday2=key;
      row.style.cssText='border-top:1px solid var(--border);border-right:1px solid var(--border);transition:background .15s';
      var isRest=!!day.rest;
      if(isRest){
        row.innerHTML='<div style="padding:12px 20px;display:flex;align-items:center;gap:8px"><span style="font-size:12px;font-weight:600;color:var(--text3)">'+day.label+'</span><span style="font-size:10px;color:var(--text3)">— Rest</span></div>';
      }else{
        var content='<div class="hx2-content" style="padding:0 20px 14px">'+hyroxSection('Warm Up',day.warmup)+hyroxSection('Workout',day.workout)+(day.core?hyroxSection('Core',day.core):'')+'</div>';
        var tickBtn='<button style="width:22px;height:22px;border-radius:50%;border:1.5px solid var(--border2);background:none;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:11px;color:transparent;flex-shrink:0;transition:all .2s;font-family:var(--sans)" onclick="event.stopPropagation();hyroxToggleDay(\''+planKey+'\','+wi+','+di+')">✓</button>';
        row.innerHTML='<div style="display:flex;align-items:center;justify-content:space-between;padding:12px 20px;cursor:pointer" onclick="hyroxToggleExpand(\''+planKey+'\','+wi+','+di+')">'
          +'<div class="hx2-label" style="font-size:13px;font-weight:600;color:var(--text)">'+day.label+'</div>'
          +tickBtn
          +'</div>'+content;
        /* Start with content visible so days are scannable */
        row.classList.add('hx2-expanded');
      }
      dc.appendChild(row);
    });
    container.appendChild(card);
  });

  /* Style ticked rows & tick buttons */
  document.querySelectorAll('.hx2-day-row').forEach(function(row){
    var key=row.dataset.hxday2;if(!key)return;
    var btn=row.querySelector('button');
    if(hyroxState[key]){
      row.style.background='rgba(201,151,58,0.06)';
      var label=row.querySelector('.hx2-label');if(label)label.style.color='var(--gold)';
      if(btn){btn.style.background='var(--gold)';btn.style.borderColor='var(--gold)';btn.style.color='var(--bg2)'}
    }
  });
}

// Watch for ticked state changes to update tick button styles
var _hxTickObserver=new MutationObserver(function(muts){
  muts.forEach(function(m){
    var row=m.target;
    var btn=row.querySelector('button');
    var label=row.querySelector('.hx2-label');
    if(row.classList.contains('hx2-ticked')){
      row.style.background='rgba(201,151,58,0.06)';
      if(label)label.style.color='var(--gold)';
      if(btn){btn.style.background='var(--gold)';btn.style.borderColor='var(--gold)';btn.style.color='var(--bg2)'}
    } else {
      row.style.background='';
      if(label)label.style.color='var(--text)';
      if(btn){btn.style.background='none';btn.style.borderColor='var(--border2)';btn.style.color='transparent'}
    }
    var content=row.querySelector('.hx2-content');
    if(content)content.style.display=row.classList.contains('hx2-expanded')?'block':'none';
  });
});

function hyroxExpandObserve(){
  document.querySelectorAll('.hx2-day-row').forEach(function(row){
    _hxTickObserver.observe(row,{attributes:true,attributeFilter:['class']});
    row.addEventListener('click',function(){
      var content=row.querySelector('.hx2-content');
      if(content)content.style.display=row.classList.contains('hx2-expanded')?'block':'none';
    });
  });
}

hyroxRenderPlan('standard');
hyroxRenderPlan('pro');
hyroxUpdateProgress();
setTimeout(hyroxExpandObserve,100);

